UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('f58bc4bf-b786-4f7b-8b91-27ca457df6af'::uuid, 'L''inflammation de la gorge cause irritation et douleur, le miel de Manuka a des propriétés apaisantes pour calmer la toux.'),('87d9c044-0eaf-42be-bbc7-9595bf5f637b'::uuid, 'Les tensions musculaires dorsales causent des douleurs, le patch chauffant détend les fibres musculaires pour une décontraction locale.'),('edab8e71-ff61-45fe-bc41-f7c36244fdcb'::uuid, 'Les contractures musculaires lombaires réduisent la mobilité, le patch chauffant augmente le flux sanguin pour détendre les muscles.'),('0a68e8ec-5507-461e-8865-2a369587917f'::uuid, 'La raideur musculaire due à la lombalgie limite le mouvement, la chaleur thérapeutique détend les muscles pour retrouver la souplesse.'),('0df4b989-29ad-40e9-aa4c-5f5ead85a9d9'::uuid, 'Le lupus peut entraîner des carences nutritionnelles, les multivitamines aident à apporter les nutriments essentiels au corps.'),('80e0151f-a322-4526-83d4-8792c16832ed'::uuid, 'Le lupus induit souvent de la fatigue, le Magnésium + B6 contribue à réduire l''épuisement cellulaire.'),('be977b20-6239-4dd8-b687-3e7893b13fde'::uuid, 'Le lupus peut affecter la flore intestinale, les probiotiques équilibrent le microbiote pour soutenir le système immunitaire.'),('e661dbc2-ca35-4979-b041-b359b8c3e99e'::uuid, 'Le mal des transports active excessivement le centre du vomissement, l''anti-nauséeux bloque ces signaux pour éviter les vomissements.'),('39aa20d2-1bfb-47a8-a965-dcde29aec2bf'::uuid, 'Le mal des transports stimule des points d''acupression, le bracelet agit sur le point P6 pour réduire les nausées.'),('a4e75ff0-a45c-473f-ad44-661a61c1c348'::uuid, 'Les nausées sont liées à la stimulation du point P6, le bracelet d''acupression module ces signaux pour prévenir le mal des transports.'),('c0ef3d17-9922-444e-bf18-03aa1003374a'::uuid, 'La Maladie de Crohn provoque souvent une dénutrition, ces compléments apportent les nutriments essentiels pour restaurer l''état nutritionnel.'),('06a61524-5a60-412e-991b-1e48624d71fd'::uuid, 'La maladie de Crohn entraîne des carences en fer et B12, leur supplémentation aide à prévenir l''anémie et la fatigue associée.'),('a3bd92c2-ae87-4160-a113-70fb0f74d025'::uuid, 'Les probiotiques Saccharomyces aident à rééquilibrer la flore intestinale perturbée, ce qui peut moduler la réponse inflammatoire dans la Maladie de Crohn.'),('1b19a227-b607-4a33-9488-40875b767d13'::uuid, 'Le magnésium et la B6 jouent un rôle dans la fonction nerveuse, leur apport aide à moduler la transmission neuronale altérée dans la maladie de Parkinson.'),('6a1127b3-7a6f-42b6-a71c-6daef7798037'::uuid, 'Une prise médicamenteuse régulière est cruciale pour optimiser l''efficacité du traitement, ce pilulier améliore l''observance en Parkinson.'),('04c83f9e-ad50-46e8-a62b-f40c94dd5e30'::uuid, 'Les troubles du sommeil sont fréquents dans la Maladie de Parkinson, la mélatonine aide à réguler le cycle veille-sommeil.'),('633d0463-bb0b-4d90-88bc-90e6b4e60cab'::uuid, 'L''inflammation de la gorge cause douleurs et picotements, ces pastilles libèrent des antiseptiques pour apaiser l''irritation et combattre l''infection locale.'),('5b50cd7c-c51e-48c6-a8ad-6fb918ebf82a'::uuid, 'Les maux de gorge sont souvent causés par des agents pathogènes, la propolis aide à désinfecter et à calmer l''inflammation de la muqueuse oropharyngée.'),('e5cb8c7e-e39a-4e71-8c16-99e1cd94fffb'::uuid, 'Les infections de la gorge entraînent une inflammation locale, ce spray antiseptique aide à réduire la charge bactérienne et l''irritation.'),('56ae6a42-687f-4d65-b30d-ff40d0e726ec'::uuid, 'Un déficit en magnésium peut augmenter la susceptibilité aux maux de tête, ce complément aide à réguler la fonction neuromusculaire.'),('b924f692-57dd-4d8f-8d04-1c0ad55e5d71'::uuid, 'La tension musculaire et oculaire contribue aux maux de tête, ce masque aide à relâcher les muscles périoculaires et à diminuer la sollicitation visuelle.'),('ff92d378-3361-4f36-832f-626a8a0bbe81'::uuid, 'Le Ginkgo biloba améliore la microcirculation cérébrale, ce qui favorise l''apport en oxygène et nutriments pour soutenir les fonctions cognitives.'),('b47bf011-fe93-45fc-a8b8-5f9f6aa86c3e'::uuid, 'Les vitamines B sont essentielles au métabolisme énergétique neuronal, leur complexe aide au bon fonctionnement des fonctions cognitives et de la mémoire.'),('90712c61-2f5c-40ea-b964-532c6d50577d'::uuid, 'Le DHA est un constituant majeur des membranes neuronales, sa supplémentation aide à maintenir l''intégrité structurelle et fonctionnelle du cerveau.'),('b7aebe3e-6cf4-4b18-8940-51010da089aa'::uuid, 'La ménopause entraîne une perte osseuse accélérée, le calcium et la vitamine D3 préviennent la déminéralisation et l''ostéoporose.'),('9a99b488-b971-469d-9962-3fa223e0d728'::uuid, 'Les carences vitaminiques peuvent apparaître pendant la ménopause, un apport en multivitamines soutient le métabolisme général.'),('d1905949-5861-44e6-b623-86036c0dae1b'::uuid, 'Les bouffées de chaleur sont dues aux fluctuations hormonales, les isoflavones de soja miment l''action des œstrogènes pour les atténuer.'),('193b10e5-da78-4949-a79d-8d11a6c6b6cc'::uuid, 'Les variations hormonales de la ménopause déclenchent les bouffées de chaleur, les isoflavones agissent comme phytoestrogènes pour réguler ces symptômes.'),('1a628edd-8a77-4f6a-a245-ba8629329db0'::uuid, 'La chute d''œstrogènes provoque une sécheresse de la muqueuse vaginale, le lubrifiant aide à restaurer l''hydratation et l''élasticité.'),('eeb6de89-1b83-401c-b0f5-ea58051e95f6'::uuid, 'Les isoflavones de soja, phyto-estrogènes naturels, aident à compenser le déficit hormonal de la ménopause, réduisant ainsi les symptômes vasculaires.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;